export enum WeatherCondition {
  SUNNY = 'ensolarado',
  CLOUDY = 'nublado',
  RAINY = 'chuvoso',
  STORM = 'tempestade',
  NIGHT = 'noite'
}

export interface WeatherData {
  temp: number;
  condition: WeatherCondition;
  description: string;
  humidity: number;
  windSpeed: number;
  feelsLike: number;
  lastUpdate: string;
}

export interface CityInfo {
