}

import { GoogleGenAI, Type } from "@google/genai";
import { WeatherCondition, WeatherData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getSimulatedWeather = async (city: string): Promise<WeatherData> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Forneça os dados climáticos atuais (simulados mas realistas baseados na estação atual) para a cidade de ${city}, Bahia. 
      Retorne APENAS um JSON válido.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            temp: { type: Type.NUMBER },
            condition: { 
              type: Type.STRING, 
              enum: ['ensolarado', 'nublado', 'chuvoso', 'tempestade', 'noite'],
              description: "A condição predominante."
            },
            description: { type: Type.STRING },
            humidity: { type: Type.NUMBER },
            windSpeed: { type: Type.NUMBER },
            feelsLike: { type: Type.NUMBER },
          },
          required: ["temp", "condition", "description", "humidity", "windSpeed", "feelsLike"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return {
      ...data,
      lastUpdate: new Date().toLocaleTimeString('pt-BR', { hour: '2xl', minute: '2-digit' })
    };
  } catch (error) {
    console.error("Error fetching weather from Gemini:", error);
    // Fallback data
    return {
      temp: 28,
      condition: WeatherCondition.RAINY,
      description: "Chuva leve passageira",
      humidity: 82,
      windSpeed: 12,
      feelsLike: 30,
      lastUpdate: "Agora"
    };
  }
};

import React, { useMemo } from 'react';

const RainEffect: React.FC = () => {
  // Create an array of rain drops with random positions and speeds
  const drops = useMemo(() => {
    return Array.from({ length: 40 }).map((_, i) => ({
      id: i,
      left: `${Math.random() * 100}%`,
      delay: `${Math.random() * 5}s`,
      duration: `${4 + Math.random() * 4}s`, // Slow duration
      opacity: 0.1 + Math.random() * 0.4,
      length: `${15 + Math.random() * 25}px`
    }));
  }, []);

  return (
    <div className="absolute inset-0 pointer-events-none overflow-hidden z-10">
      {drops.map((drop) => (
        <div
          key={drop.id}
          className="absolute bg-white rounded-full"
          style={{
            left: drop.left,
            top: '-50px',
            width: '1.5px',
            height: drop.length,
            opacity: drop.opacity,
            animation: `fall ${drop.duration} linear infinite`,
            animationDelay: drop.delay,
            filter: 'blur(0.5px)'
          }}
        />
      ))}
      <style>{`
        @keyframes fall {
          to {
            transform: translateY(110vh);
          }
        }
      `}</style>
    </div>
  );
};

export default RainEffect;

