    if (!weather) return 'from-slate-900 to-black';
    switch (weather.condition) {
      case WeatherCondition.SUNNY: return 'from-blue-400 via-blue-500 to-blue-700';
      case WeatherCondition.RAINY: return 'from-slate-700 via-slate-800 to-slate-900';
      case WeatherCondition.STORM: return 'from-indigo-900 via-purple-900 to-black';
      case WeatherCondition.CLOUDY: return 'from-blue-200 via-slate-400 to-slate-600';
      case WeatherCondition.NIGHT: return 'from-slate-900 via-black to-blue-950';
      default: return 'from-blue-500 to-blue-900';
    }
  };

  const getWeatherIcon = () => {
    if (!weather) return <Cloud className="w-24 h-24 text-white" />;
    const iconClass = "w-24 h-24 text-white drop-shadow-lg animate-pulse";
    switch (weather.condition) {
      case WeatherCondition.SUNNY: return <Sun className={iconClass} />;
      case WeatherCondition.RAINY: return <CloudRain className={iconClass} />;
      case WeatherCondition.STORM: return <CloudLightning className={iconClass} />;
      case WeatherCondition.NIGHT: return <Moon className={iconClass} />;
      default: return <Cloud className={iconClass} />;
    }
  };

  const isRaining = weather?.condition === WeatherCondition.RAINY || weather?.condition === WeatherCondition.STORM;

  return (
    <div className="flex justify-center items-center w-full h-screen bg-neutral-900">
      {/* 9:16 Aspect Ratio Container */}
      <div 
        className={`relative w-full h-full max-w-[450px] aspect-[9/16] bg-gradient-to-b ${getBackgroundClass()} overflow-hidden transition-all duration-1000 ease-in-out shadow-2xl flex flex-col items-center px-6 py-12 text-white`}
      >
        {/* Dynamic Rain Overlay */}
        {isRaining && <RainEffect />}

        {/* Header */}
        <div className="z-20 flex flex-col items-center w-full">
          <div className="flex items-center gap-2 mb-1 bg-white/10 px-4 py-1.5 rounded-full border border-white/20">
            <MapPin className="w-4 h-4 text-red-400" />
            <h1 className="text-sm font-bold tracking-widest uppercase">Simões Filho, BA</h1>
          </div>
          <p className="text-xs text-white/60 mb-8">Nordeste do Brasil</p>
        </div>

