          <div className="flex-1 flex flex-col items-center justify-center z-20">
            <div className="animate-spin mb-4">
              <RefreshCw className="w-8 h-8 text-white/40" />
            </div>
            <p className="text-white/40 font-medium">Consultando Gemini...</p>
          </div>
        ) : weather ? (
          <div className="flex-1 flex flex-col items-center w-full z-20">
            {/* Main Weather Display */}
            <div className="flex flex-col items-center mt-4 mb-8">
              <div className="relative mb-6">
                {getWeatherIcon()}
                <div className="absolute -inset-4 bg-white/20 blur-3xl rounded-full -z-10" />
              </div>

