import { GoogleGenAI, Type } from "@google/genai";
import { WeatherCondition, WeatherData, NewsItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getSimulatedWeather = async (city: string): Promise<WeatherData> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Forneça os dados climáticos atuais e uma previsão para os próximos 3 dias para a cidade de ${city}, Bahia. 
      Retorne APENAS um JSON válido seguindo exatamente o schema fornecido.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            temp: { type: Type.NUMBER },
            condition: { 
              type: Type.STRING, 
              enum: ['ensolarado', 'nublado', 'chuvoso', 'tempestade', 'noite'],
              description: "A condição predominante atual."
            },
            description: { type: Type.STRING },
            humidity: { type: Type.NUMBER },
            windSpeed: { type: Type.NUMBER },
            feelsLike: { type: Type.NUMBER },
            forecast: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  day: { type: Type.STRING, description: "Abreviatura do dia da semana (ex: Seg, Ter)." },
                  tempMin: { type: Type.NUMBER },
                  tempMax: { type: Type.NUMBER },
                  condition: { 
                    type: Type.STRING, 
                    enum: ['ensolarado', 'nublado', 'chuvoso', 'tempestade', 'noite']
                  }
                },
                required: ["day", "tempMin", "tempMax", "condition"]
              }
            }
          },
          required: ["temp", "condition", "description", "humidity", "windSpeed", "feelsLike", "forecast"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return {
      ...data,
      lastUpdate: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
    };
  } catch (error) {
    console.error("Error fetching weather from Gemini:", error);
    return {
      temp: 28,
      condition: WeatherCondition.RAINY,
      description: "Chuva leve passageira",
      humidity: 82,
      windSpeed: 12,
      feelsLike: 30,
      lastUpdate: "Agora",
      forecast: [
        { day: 'Amanhã', tempMin: 23, tempMax: 29, condition: WeatherCondition.RAINY },
        { day: 'Qua', tempMin: 22, tempMax: 30, condition: WeatherCondition.CLOUDY },
        { day: 'Qui', tempMin: 24, tempMax: 32, condition: WeatherCondition.SUNNY }
      ]
    };
  }
};

